#include <stdio.h>
#include <stdlib.h>

long long gcd_ll(long long x, long long y) {
    while (y) {
        long long t = x % y;
        x = y;
        y = t;
    }
    return x;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long a, b;
        scanf("%lld %lld", &a, &b);
        long long g;
        while ((g = gcd_ll(a, b)) > 1) {
            a /= g;
        }
        if (a == 1) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

