#!/usr/bin/env python3
import sys, math

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        a = int(next(it)); b = int(next(it))
        while True:
            g = math.gcd(a, b)
            if g == 1:
                break
            a //= g
        out.append('YES' if a == 1 else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

