const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let res = [];
function gcd(a, b) {
  while (b !== 0) {
    const t = a % b;
    a = b;
    b = t;
  }
  return a;
}
for (let i = 0; i < T; i++) {
  let a = Number(input[idx++]);
  const b = Number(input[idx++]);
  while (true) {
    const g = gcd(a, b);
    if (g === 1) break;
    a = Math.floor(a / g);
  }
  res.push(a === 1 ? 'YES' : 'NO');
}
console.log(res.join('\n'));

